{"ideviceId":"idevice-1780944611371-y8tx46mih","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<p><br /></p>
<style>
  :root {
    --bg: #0f0f1a;
    --card: #1a1a2e;
    --card2: #16213e;
    --accent1: #a78bfa;   /* violeta suave */
    --accent2: #34d399;   /* menta */
    --accent3: #f472b6;   /* rosa */
    --accent4: #fbbf24;   /* amarillo */
    --text: #e2e8f0;
    --muted: #94a3b8;
    --border: #2d2d4e;
    --correct: #34d399;
    --wrong: #f87171;
    --radius: 18px;
    --shadow: 0 8px 32px rgba(0,0,0,0.45);
  }

  * { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: 'Nunito', sans-serif;
    background: var(--bg);
    color: var(--text);
    min-height: 100vh;
    padding: 0;
    overflow-x: hidden;
  }

  /* ── FONDO ANIMADO ── */
  body::before {
    content: '';
    position: fixed; inset: 0; z-index: 0;
    background:
      radial-gradient(ellipse 80% 60% at 20% 20%, rgba(167,139,250,.18) 0%, transparent 60%),
      radial-gradient(ellipse 60% 50% at 80% 80%, rgba(244,114,182,.14) 0%, transparent 60%),
      radial-gradient(ellipse 50% 40% at 60% 30%, rgba(52,211,153,.10) 0%, transparent 60%);
    pointer-events: none;
    animation: bgPulse 8s ease-in-out infinite alternate;
  }
  @keyframes bgPulse {
    from { opacity: 1; }
    to   { opacity: 0.7; }
  }

  .container {
    position: relative; z-index: 1;
    max-width: 820px;
    margin: 0 auto;
    padding: 28px 18px 60px;
  }

  /* ── HEADER ── */
  .hero {
    text-align: center;
    padding: 36px 20px 28px;
    background: linear-gradient(135deg, rgba(167,139,250,.15), rgba(52,211,153,.10));
    border: 1px solid var(--border);
    border-radius: 28px;
    margin-bottom: 32px;
    backdrop-filter: blur(8px);
    box-shadow: var(--shadow);
    animation: slideDown .6s ease;
  }
  @keyframes slideDown { from{opacity:0;transform:translateY(-30px)} to{opacity:1;transform:translateY(0)} }

  .hero-emoji { font-size: 3.6rem; display: block; margin-bottom: 10px; animation: float 3s ease-in-out infinite; }
  @keyframes float { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-10px)} }

  .hero h1 {
    font-family: 'Pacifico', cursive;
    font-size: clamp(1.6rem, 5vw, 2.4rem);
    background: linear-gradient(90deg, var(--accent1), var(--accent3), var(--accent2));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    margin-bottom: 8px;
    line-height: 1.2;
  }

  .hero p {
    color: var(--muted);
    font-size: .95rem;
    margin-top: 6px;
  }

  .badge {
    display: inline-block;
    background: rgba(167,139,250,.2);
    border: 1px solid rgba(167,139,250,.4);
    color: var(--accent1);
    font-size: .78rem;
    font-weight: 700;
    padding: 4px 14px;
    border-radius: 50px;
    margin-bottom: 12px;
    letter-spacing: .04em;
    text-transform: uppercase;
  }

  /* ── BARRA PROGRESO ── */
  .progress-wrap {
    background: rgba(255,255,255,.06);
    border-radius: 50px;
    height: 10px;
    margin: 20px 0 6px;
    overflow: hidden;
    border: 1px solid var(--border);
  }
  .progress-bar {
    height: 100%;
    border-radius: 50px;
    background: linear-gradient(90deg, var(--accent1), var(--accent3));
    transition: width .5s ease;
    width: 0%;
  }
  .progress-label {
    font-size: .8rem;
    color: var(--muted);
    text-align: right;
  }

  /* ── SCORE CHIP ── */
  .score-chip {
    display: flex;
    align-items: center;
    gap: 10px;
    background: rgba(52,211,153,.1);
    border: 1px solid rgba(52,211,153,.3);
    border-radius: 50px;
    padding: 8px 20px;
    margin: 0 auto 24px;
    width: fit-content;
    font-weight: 700;
    color: var(--accent2);
    font-size: 1.05rem;
    transition: all .3s;
  }
  .score-chip .score-num { font-size: 1.4rem; }

  /* ── TARJETA DE PREGUNTA ── */
  .q-card {
    background: var(--card);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 26px 24px;
    margin-bottom: 22px;
    box-shadow: var(--shadow);
    animation: fadeUp .5s ease both;
    position: relative;
    overflow: hidden;
  }
  .q-card::before {
    content: '';
    position: absolute;
    top: 0; left: 0;
    width: 4px; height: 100%;
    border-radius: 4px 0 0 4px;
  }
  .q-card:nth-child(1)::before { background: var(--accent1); }
  .q-card:nth-child(2)::before { background: var(--accent3); }
  .q-card:nth-child(3)::before { background: var(--accent2); }
  .q-card:nth-child(4)::before { background: var(--accent4); }
  .q-card:nth-child(5)::before { background: #60a5fa; }
  .q-card:nth-child(6)::before { background: var(--accent1); }
  .q-card:nth-child(7)::before { background: var(--accent3); }
  .q-card:nth-child(8)::before { background: var(--accent2); }
  .q-card:nth-child(9)::before { background: var(--accent4); }
  .q-card:nth-child(10)::before { background: #60a5fa; }

  @keyframes fadeUp {
    from{opacity:0;transform:translateY(20px)}
    to{opacity:1;transform:translateY(0)}
  }

  .q-num {
    font-size: .72rem;
    font-weight: 900;
    letter-spacing: .1em;
    text-transform: uppercase;
    color: var(--muted);
    margin-bottom: 10px;
  }

  .q-icon { font-size: 1.7rem; margin-right: 8px; vertical-align: middle; }

  .q-text {
    font-size: 1.05rem;
    font-weight: 700;
    color: var(--text);
    line-height: 1.5;
    margin-bottom: 18px;
  }

  /* ── OPCIONES ── */
  .options { display: grid; gap: 10px; }

  .option-btn {
    background: rgba(255,255,255,.04);
    border: 1.5px solid var(--border);
    border-radius: 12px;
    padding: 13px 18px;
    color: var(--text);
    font-family: 'Nunito', sans-serif;
    font-size: .92rem;
    font-weight: 600;
    text-align: left;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 12px;
    transition: all .2s;
    position: relative;
    overflow: hidden;
  }
  .option-btn:hover:not(:disabled) {
    background: rgba(167,139,250,.12);
    border-color: var(--accent1);
    transform: translateX(4px);
  }
  .option-btn:disabled { cursor: default; }
  .option-btn.correct {
    background: rgba(52,211,153,.15);
    border-color: var(--correct);
    color: var(--correct);
  }
  .option-btn.wrong {
    background: rgba(248,113,113,.12);
    border-color: var(--wrong);
    color: var(--wrong);
  }

  .opt-letter {
    width: 28px; height: 28px;
    border-radius: 50%;
    background: rgba(255,255,255,.08);
    display: flex; align-items: center; justify-content: center;
    font-size: .8rem;
    font-weight: 900;
    flex-shrink: 0;
    transition: all .2s;
  }
  .option-btn.correct .opt-letter { background: var(--correct); color: #0f0f1a; }
  .option-btn.wrong   .opt-letter { background: var(--wrong);   color: #0f0f1a; }

  /* ── FEEDBACK ── */
  .feedback-msg {
    margin-top: 14px;
    padding: 10px 16px;
    border-radius: 10px;
    font-size: .88rem;
    font-weight: 700;
    display: none;
  }
  .feedback-msg.show { display: block; }
  .feedback-msg.ok { background: rgba(52,211,153,.12); color: var(--correct); border: 1px solid rgba(52,211,153,.3); }
  .feedback-msg.no { background: rgba(248,113,113,.10); color: var(--wrong); border: 1px solid rgba(248,113,113,.3); }

  /* ── INPUT ── */
  .open-q textarea {
    width: 100%;
    background: rgba(255,255,255,.05);
    border: 1.5px solid var(--border);
    border-radius: 12px;
    color: var(--text);
    font-family: 'Nunito', sans-serif;
    font-size: .93rem;
    padding: 14px 16px;
    resize: vertical;
    min-height: 90px;
    transition: border .2s;
    outline: none;
  }
  .open-q textarea:focus { border-color: var(--accent1); }
  .open-q label { font-size: .85rem; color: var(--muted); font-weight: 700; margin-bottom: 8px; display: block; }

  /* ── MATCH ── */
  .match-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-top: 4px; }
  .match-pair {
    display: flex; flex-direction: column; gap: 6px;
  }
  .match-concept {
    background: rgba(167,139,250,.12);
    border: 1px solid rgba(167,139,250,.3);
    border-radius: 10px;
    padding: 10px 14px;
    font-size: .88rem;
    font-weight: 700;
    color: var(--accent1);
    text-align: center;
  }
  .match-select {
    background: rgba(255,255,255,.05);
    border: 1.5px solid var(--border);
    border-radius: 10px;
    color: var(--text);
    font-family: 'Nunito', sans-serif;
    font-size: .85rem;
    padding: 9px 12px;
    outline: none;
    cursor: pointer;
    transition: border .2s;
    -webkit-appearance: none;
    appearance: none;
    width: 100%;
  }
  .match-select:focus { border-color: var(--accent1); }
  .match-select.correct-sel { border-color: var(--correct); color: var(--correct); }
  .match-select.wrong-sel   { border-color: var(--wrong);   color: var(--wrong);   }

  /* ── SECCIÓN DATOS ── */
  .form-section {
    background: var(--card2);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 26px 24px;
    margin-bottom: 22px;
    box-shadow: var(--shadow);
  }
  .form-section h3 {
    font-size: 1rem;
    font-weight: 900;
    margin-bottom: 18px;
    color: var(--accent1);
    display: flex; gap: 8px; align-items: center;
  }
  .form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; }
  @media(max-width:520px){ .form-row{ grid-template-columns:1fr; } .match-grid{grid-template-columns:1fr;} }
  .form-field { display: flex; flex-direction: column; gap: 6px; }
  .form-field label { font-size: .82rem; font-weight: 700; color: var(--muted); }
  .form-field input {
    background: rgba(255,255,255,.05);
    border: 1.5px solid var(--border);
    border-radius: 10px;
    color: var(--text);
    font-family: 'Nunito', sans-serif;
    font-size: .93rem;
    padding: 11px 14px;
    outline: none;
    transition: border .2s;
    width: 100%;
  }
  .form-field input:focus { border-color: var(--accent1); }

  /* ── BOTÓN ── */
  .btn-send {
    display: block;
    width: 100%;
    padding: 16px;
    background: linear-gradient(135deg, var(--accent1), var(--accent3));
    color: #fff;
    font-family: 'Nunito', sans-serif;
    font-size: 1.05rem;
    font-weight: 900;
    border: none;
    border-radius: 14px;
    cursor: pointer;
    transition: all .3s;
    box-shadow: 0 4px 20px rgba(167,139,250,.3);
    margin-top: 10px;
    letter-spacing: .02em;
  }
  .btn-send:hover:not(:disabled) {
    transform: translateY(-2px);
    box-shadow: 0 8px 30px rgba(167,139,250,.45);
  }
  .btn-send:disabled { opacity: .6; cursor: not-allowed; }

  .check-btn {
    background: rgba(167,139,250,.12);
    border: 1.5px solid rgba(167,139,250,.4);
    color: var(--accent1);
    font-family: 'Nunito', sans-serif;
    font-size: .85rem;
    font-weight: 800;
    padding: 8px 18px;
    border-radius: 50px;
    cursor: pointer;
    margin-top: 14px;
    transition: all .2s;
  }
  .check-btn:hover { background: rgba(167,139,250,.22); }

  /* ── RESULTADO FINAL ── */
  #resultado-final {
    display: none;
    text-align: center;
    background: var(--card);
    border: 1px solid var(--border);
    border-radius: 28px;
    padding: 40px 28px;
    box-shadow: var(--shadow);
    animation: fadeUp .6s ease;
  }
  #resultado-final .big-emoji { font-size: 4.5rem; animation: float 3s ease-in-out infinite; }
  #resultado-final h2 {
    font-family: 'Pacifico', cursive;
    font-size: 2rem;
    background: linear-gradient(90deg, var(--accent1), var(--accent3));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    margin: 14px 0 8px;
  }
  #resultado-final p { color: var(--muted); font-size: .95rem; line-height: 1.6; }

  .score-display {
    font-size: 3.5rem;
    font-weight: 900;
    background: linear-gradient(90deg, var(--accent2), var(--accent1));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    margin: 18px 0 4px;
  }

  /* ── SECCIÓN TÍTULOS ── */
  .section-title {
    font-size: .72rem;
    font-weight: 900;
    letter-spacing: .12em;
    text-transform: uppercase;
    color: var(--accent1);
    margin: 32px 0 14px;
    display: flex; align-items: center; gap: 10px;
  }
  .section-title::after {
    content: '';
    flex: 1;
    height: 1px;
    background: linear-gradient(90deg, rgba(167,139,250,.4), transparent);
  }

  /* ── SPINNER ── */
  .spinner {
    display: inline-block;
    width: 16px; height: 16px;
    border: 2px solid rgba(255,255,255,.3);
    border-top-color: #fff;
    border-radius: 50%;
    animation: spin .7s linear infinite;
    margin-right: 8px;
    vertical-align: middle;
  }
  @keyframes spin { to{transform:rotate(360deg)} }

  /* animaciones retrasadas */
  .q-card:nth-child(1){animation-delay:.05s}
  .q-card:nth-child(2){animation-delay:.1s}
  .q-card:nth-child(3){animation-delay:.15s}
  .q-card:nth-child(4){animation-delay:.2s}
  .q-card:nth-child(5){animation-delay:.25s}
  .q-card:nth-child(6){animation-delay:.3s}
  .q-card:nth-child(7){animation-delay:.35s}
  .q-card:nth-child(8){animation-delay:.4s}
</style>
<div class="container"><!-- HERO -->
<div class="hero"><span class="badge">📚 Primer Semestre · Desarrollo Personal</span> <span class="hero-emoji">🌱🧠💚</span>
<h1>Evaluación: Autocuidado como Vida Reflexiva</h1>
<p>Tema 3 · Diseño de Ambientes: Salud Mental</p>
<div class="progress-wrap">
<div class="progress-bar" id="progreso"></div>
</div>
<div class="progress-label" id="prog-label">0 / 70 pts</div>
</div>
<div class="score-chip"><span>⭐</span> <span class="score-num" id="puntos">0</span> <span>puntos acumulados</span></div>
<!-- ════════════════════════════════
       SECCIÓN 1 · OPCIÓN MÚLTIPLE
       ════════════════════════════════ -->
<div class="section-title">Sección I · Opción múltiple</div>
<!-- P1 -->
<div class="q-card">
<div class="q-num">Pregunta 1 de 10</div>
<p class="q-text"><span class="q-icon">🌿</span>¿Cuál de las siguientes afirmaciones describe <strong>mejor</strong> el autocuidado según la Organización Mundial de la Salud?</p>
<div class="options" id="quiz1"><button class="option-btn" onclick="verificar('quiz1',0,0,'✅ Correcto. La OMS define el autocuidado como acciones intencionales para preservar la salud física, mental, emocional y social.',this)"><span class="opt-letter">A</span>Acciones intencionales para el bienestar físico, mental, emocional y social</button> <button class="option-btn" onclick="verificar('quiz1',1,0,'❌ Solo el ejercicio y la dieta son aspectos físicos; el autocuidado es más amplio.',this)"><span class="opt-letter">B</span>Solo hacer ejercicio y seguir una dieta balanceada</button> <button class="option-btn" onclick="verificar('quiz1',2,0,'❌ El autocuidado requiere intencionalidad y reflexión, no es espontáneo.',this)"><span class="opt-letter">C</span>Cualquier acción espontánea que hagamos sin pensar</button> <button class="option-btn" onclick="verificar('quiz1',3,0,'❌ El autocuidado es una responsabilidad, no un lujo exclusivo.',this)"><span class="opt-letter">D</span>Un lujo para personas con mucho tiempo libre</button></div>
<div class="feedback-msg" id="fb-quiz1"></div>
</div>
<!-- P2 -->
<div class="q-card">
<div class="q-num">Pregunta 2 de 10</div>
<p class="q-text"><span class="q-icon">📅</span>Valeria tiene mucho estrés por los exámenes. Decide <em>organizar su horario de estudio, ordenar su cuarto y planificar sus tareas</em>. ¿Qué tipo de autocuidado practica?</p>
<div class="options" id="quiz2"><button class="option-btn" onclick="verificar('quiz2',0,2,'❌ Físico implica ejercicio, sueño y alimentación.',this)"><span class="opt-letter">A</span>Físico</button> <button class="option-btn" onclick="verificar('quiz2',1,2,'❌ Emocional se enfoca en gestión de sentimientos.',this)"><span class="opt-letter">B</span>Emocional</button> <button class="option-btn" onclick="verificar('quiz2',2,2,'✅ Correcto. Organizar tiempos y espacios es autocuidado práctico.',this)"><span class="opt-letter">C</span>Práctico</button> <button class="option-btn" onclick="verificar('quiz2',3,2,'❌ Espiritual se relaciona con sentido y trascendencia personal.',this)"><span class="opt-letter">D</span>Espiritual</button></div>
<div class="feedback-msg" id="fb-quiz2"></div>
</div>
<!-- P3 -->
<div class="q-card">
<div class="q-num">Pregunta 3 de 10</div>
<p class="q-text"><span class="q-icon">😴</span>¿Cuántas horas de sueño se recomiendan para un adolescente dentro del autocuidado físico?</p>
<div class="options" id="quiz3"><button class="option-btn" onclick="verificar('quiz3',0,1,'❌ 4-5 horas son insuficientes y afectan la concentración.',this)"><span class="opt-letter">A</span>4 a 5 horas</button> <button class="option-btn" onclick="verificar('quiz3',1,1,'✅ Correcto. Los expertos recomiendan 8-10 horas para adolescentes.',this)"><span class="opt-letter">B</span>8 a 10 horas</button> <button class="option-btn" onclick="verificar('quiz3',2,1,'❌ Dormir 12+ horas también puede indicar problemas de salud.',this)"><span class="opt-letter">C</span>12 o más horas</button> <button class="option-btn" onclick="verificar('quiz3',3,1,'❌ 6 horas no son suficientes para el desarrollo adolescente.',this)"><span class="opt-letter">D</span>Solo 6 horas está bien</button></div>
<div class="feedback-msg" id="fb-quiz3"></div>
</div>
<!-- P4 -->
<div class="q-card">
<div class="q-num">Pregunta 4 de 10</div>
<p class="q-text"><span class="q-icon">🚫</span>¿Cuál de los siguientes <strong>NO</strong> es un beneficio del autocuidado regular?</p>
<div class="options" id="quiz4"><button class="option-btn" onclick="verificar('quiz4',0,0,'✅ Correcto. Acumular estrés sin gestionarlo es lo OPUESTO al autocuidado.',this)"><span class="opt-letter">A</span>Acumular más estrés sin gestionarlo</button> <button class="option-btn" onclick="verificar('quiz4',1,0,'❌ La resiliencia SÍ es un beneficio real del autocuidado.',this)"><span class="opt-letter">B</span>Mayor resiliencia ante los retos</button> <button class="option-btn" onclick="verificar('quiz4',2,0,'❌ El rendimiento académico SÍ mejora con el autocuidado.',this)"><span class="opt-letter">C</span>Mejor rendimiento académico</button> <button class="option-btn" onclick="verificar('quiz4',3,0,'❌ El sistema inmune SÍ se fortalece con el autocuidado.',this)"><span class="opt-letter">D</span>Fortalecimiento del sistema inmune</button></div>
<div class="feedback-msg" id="fb-quiz4"></div>
</div>
<!-- P5 -->
<div class="q-card">
<div class="q-num">Pregunta 5 de 10</div>
<p class="q-text"><span class="q-icon">🪞</span>Una "vida reflexiva" en el contexto del autocuidado significa que:</p>
<div class="options" id="quiz5"><button class="option-btn" onclick="verificar('quiz5',0,1,'❌ Aislarse no es reflexión, puede ser evasión.',this)"><span class="opt-letter">A</span>Te aíslas de los demás para pensar solo/a</button> <button class="option-btn" onclick="verificar('quiz5',1,1,'✅ Correcto. Significa observarte, identificar tus necesidades y actuar en consecuencia.',this)"><span class="opt-letter">B</span>Te observas, identificas tus necesidades y actúas en consecuencia</button> <button class="option-btn" onclick="verificar('quiz5',2,1,'❌ Leer filosofía puede ayudar, pero no es la definición central.',this)"><span class="opt-letter">C</span>Lees libros de filosofía todos los días</button> <button class="option-btn" onclick="verificar('quiz5',3,1,'❌ Ignorar emociones es lo contrario al autocuidado emocional.',this)"><span class="opt-letter">D</span>Ignoras tus emociones para ser más racional</button></div>
<div class="feedback-msg" id="fb-quiz5"></div>
</div>
<!-- P6 -->
<div class="q-card">
