<script>
  // ── ESTADO ──
  let puntosTotal = 0;
  const maxPuntos = 70;
  const respondidas = {};
  let matchDone = false;

  // Fecha automática
  document.getElementById('fecha-campo').value = new Date().toLocaleDateString('es-MX',{day:'2-digit',month:'long',year:'numeric'});

  // ── QUIZ OPCIÓN MÚLTIPLE ──
  function verificar(quizId, idx, correctIdx, feedback, btn) {
    if (respondidas[quizId]) return;
    respondidas[quizId] = idx;

    const quiz = document.getElementById(quizId);
    const btns = quiz.querySelectorAll('.option-btn');
    btns.forEach(b => b.disabled = true);

    const fbEl = document.getElementById('fb-' + quizId);
    const correcto = (idx === correctIdx);

    btns[correctIdx].classList.add('correct');
    if (!correcto) btn.classList.add('wrong');

    fbEl.textContent = feedback;
    fbEl.className = 'feedback-msg show ' + (correcto ? 'ok' : 'no');

    if (correcto) {
      puntosTotal += 10;
      actualizarPuntos();
    }
  }

  // ── RELACIONAR COLUMNAS ──
  const matchAnswers = { m1:'Físico', m2:'Emocional', m3:'Social', m4:'Práctico' };

  function verificarMatch() {
    if (matchDone) return;
    matchDone = true;

    let correctas = 0;
    for (const [id, ans] of Object.entries(matchAnswers)) {
      const sel = document.getElementById(id);
      sel.disabled = true;
      if (sel.value === ans) {
        sel.classList.add('correct-sel');
        correctas++;
      } else {
        sel.classList.add('wrong-sel');
      }
    }

    const pts = correctas * 5;
    puntosTotal += pts;
    actualizarPuntos();

    const fbEl = document.getElementById('fb-match');
    fbEl.textContent = correctas === 4
      ? `✅ ¡Perfecto! Las 4 relaciones son correctas. +${pts} pts`
      : `📝 ${correctas} de 4 correctas. +${pts} pts. Las marcadas en rojo no son correctas.`;
    fbEl.className = 'feedback-msg show ' + (correctas === 4 ? 'ok' : 'no');
  }

  // ── PUNTOS ──
  function actualizarPuntos() {
    document.getElementById('puntos').textContent = puntosTotal;
    const pct = Math.round((puntosTotal / maxPuntos) * 100);
    document.getElementById('progreso').style.width = pct + '%';
    document.getElementById('prog-label').textContent = puntosTotal + ' / ' + maxPuntos + ' pts';
  }

  // ── ENVÍO ──
  async function enviarResultados() {
    const nombre = document.getElementById('nombre').value.trim();
    const correoAlumno = document.getElementById('correo-alumno').value.trim();
    const grupo = document.getElementById('grupo').value.trim();
    const r1 = document.getElementById('r1').value.trim();
    const r2 = document.getElementById('r2').value.trim();
    const r3 = document.getElementById('r3').value.trim();

    if (!nombre || !correoAlumno) {
      alert('⚠️ Por favor, ingresa tu nombre y correo electrónico.');
      return;
    }
    if (!r1 || !r2 || !r3) {
      alert('⚠️ Por favor, completa las 3 preguntas de reflexión antes de enviar.');
      return;
    }

    const btn = document.getElementById('btn-enviar');
    btn.disabled = true;
    btn.innerHTML = '<span class="spinner"></span>Enviando…';

    const quizNombres = {
      quiz1:'P1 – Definición OMS',
      quiz2:'P2 – Caso Valeria',
      quiz3:'P3 – Horas de sueño',
      quiz4:'P4 – No es beneficio',
      quiz5:'P5 – Vida reflexiva',
      quiz6:'P6 – Rendimiento escolar',
    };

    let quizResumen = '';
    for (const [qid, qn] of Object.entries(quizNombres)) {
      const resp = respondidas[qid] !== undefined
        ? 'Opción ' + ['A','B','C','D'][respondidas[qid]]
        : 'Sin responder';
      quizResumen += qn + ': ' + resp + '\n';
    }

    const cuerpo = `
📋 EVALUACIÓN – TEMA 3: AUTOCUIDADO COMO VIDA REFLEXIVA
────────────────────────────────────────────────────────
👤 Estudiante : ${nombre}
📧 Correo     : ${correoAlumno}
🏫 Grupo      : ${grupo || 'No especificado'}
📅 Fecha      : ${new Date().toLocaleDateString('es-MX')}
⭐ Puntuación : ${puntosTotal} / ${maxPuntos} pts

SECCIÓN I – OPCIÓN MÚLTIPLE:
${quizResumen}

SECCIÓN II – RELACIONAR COLUMNAS:
Ejercicio → ${document.getElementById('m1').value || '–'}
Diario emocional → ${document.getElementById('m2').value || '–'}
Llamar a alguien → ${document.getElementById('m3').value || '–'}
Organizar agenda → ${document.getElementById('m4').value || '–'}

SECCIÓN III – REFLEXIONES:
1. ${r1}

2. ${r2}

3. ${r3}
────────────────────────────────────────────────────────
Enviado desde la evaluación interactiva · Diseño de Ambientes: Salud Mental
    `.trim();

    try {
      if (typeof emailjs !== 'undefined') {
        await emailjs.send('service_autocuidado','template_autocuidado',{
          to_email: 'astridfernandar648@gmail.com',
          from_name: nombre,
          from_email: correoAlumno,
          subject: '📚 Evaluación Tema 3 – ' + nombre,
          message: cuerpo,
          puntuacion: puntosTotal + '/' + maxPuntos,
          grupo: grupo || 'No especificado'
        });
      } else { throw new Error('no emailjs'); }
    } catch(e) {
      const subj = encodeURIComponent('📚 Evaluación Tema 3 Autocuidado – ' + nombre);
      const body = encodeURIComponent(cuerpo);
      window.open('mailto:astridfernandar648@gmail.com?subject=' + subj + '&body=' + body);
    }

    mostrarFinal(nombre);
  }

  function mostrarFinal(nombre) {
    document.getElementById('form-envio').style.display = 'none';
    const div = document.getElementById('resultado-final');
    div.style.display = 'block';
    div.scrollIntoView({ behavior:'smooth' });
    document.getElementById('score-final-num').textContent = puntosTotal;
    document.getElementById('progreso').style.width = '100%';

    let emoji = '📚', titulo = 'Sigue aprendiendo';
    if (puntosTotal >= 60)      { emoji = '🏆'; titulo = '¡Excelente desempeño!'; }
    else if (puntosTotal >= 40) { emoji = '👏'; titulo = '¡Bien hecho!'; }
    else if (puntosTotal >= 25) { emoji = '😊'; titulo = '¡Buen trabajo!'; }

    document.getElementById('emoji-result').textContent = emoji;
    document.getElementById('titulo-result').textContent = titulo;
    document.getElementById('msg-result').textContent =
      nombre + ', tu evaluación del Tema 3 fue enviada al correo del docente. ¡Recuerda poner en práctica el autocuidado cada día!';
  }
</script>
